fun order(item: String, qty: Int = 1, express: Boolean = false) {
    println("$item x$qty express=$express")
}
order("Book", express = true)

fun sendEmail(to: String, cc: String? = null) {
    println("To: $to, CC: $cc")
}
sendEmail("a@b.com")

fun log(msg: String, verbose: Boolean = false) {
    if (verbose) print("[VERBOSE] ")
    println(msg)
}
log("Started")
log("Details", verbose = true)

fun createRect(width: Int, height: Int) {
    println("${width}x${height}")
}
createRect(height = 5, width = 10)

fun connect(host: String, port: Int = 443, tls: Boolean = true) {
    println("$host:$port tls=$tls")
}
connect("api.example.com", tls = false)
